/// Look up `nr` in the dense by-number index. Returns nullptr if unknown.
inline const LinuxSyscallEntry* LinuxSyscallLookup(u64 nr)
{
    if (nr > kLinuxSyscallMaxNumber)
        return nullptr;
    return kLinuxSyscallByNumber[static_cast<u32>(nr)];
}

